/* ASN1T_MatchingUEidPerGP_Item_matchedPerGP */

ASN1T_MatchingUEidPerGP_Item_matchedPerGP* 
   new_ASN1T_MatchingUEidPerGP_Item_matchedPerGP (ASN1CType& ccobj)
{
   void* pdata = ccobj.memAlloc (sizeof(ASN1T_MatchingUEidPerGP_Item_matchedPerGP));
   if (0 == pdata) return 0;
   else return new (pdata) ASN1T_MatchingUEidPerGP_Item_matchedPerGP;
}

int asn1Init_MatchingUEidPerGP_Item_matchedPerGP (
   ASN1T_MatchingUEidPerGP_Item_matchedPerGP* pvalue, 
   OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   if (free) {
      asn1Free_MatchingUEidPerGP_Item_matchedPerGP (pctxt, pvalue);
   }
   else {
      pvalue->t = 0;
      OSCRTLMEMSET (&pvalue->u, 0, sizeof(pvalue->u));
   }
   return 0;
}

void asn1Free_MatchingUEidPerGP_Item_matchedPerGP (OSCTXT *pctxt, 
   ASN1T_MatchingUEidPerGP_Item_matchedPerGP* pvalue)
{
   if (0 == pvalue) return;
   switch (pvalue->t) {
      case 0: break; /* no choice; nothing to free */
      case 1:
         break;

      case 2:
         if (0 != pvalue->u.oneOrMoreUEmatched) {
            asn1Free_MatchingUEidList_PerGP (pctxt, pvalue->u.oneOrMoreUEmatched);
            rtxMemFreePtr (pctxt, (void*)pvalue->u.oneOrMoreUEmatched);
            pvalue->u.oneOrMoreUEmatched = 0;
         }
         break;

      default:
         if (0 != pvalue->u.extElem1) {
            if (!rtxCtxtTestFlag (pctxt, ASN1FASTCOPY)) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1->data);
               pvalue->u.extElem1->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1);
            pvalue->u.extElem1 = 0;
         }
   }
}

